import unittestfrom tiles import Tile, Cherry, Bee, Apple, Wall, Portalimport osclass TestTile(unittest.TestCase):    """Test cases for the Tile base class."""    def setUp(self):        """Set up test fixtures for Tile tests."""        self.default_tile = Tile((0, 0))        self.weighted_tile = Tile((1, 1), weight=5)        self.enclosed_tile = Tile((2, 2), enclosed=True)        self.rat_tile = Tile((3, 3), has_rat=True)    def test_init_default_values(self):        """Test Tile initialization with default values."""        tile = Tile((0, 0))        self.assertEqual(tile.pos, (0, 0))        self.assertEqual(tile.weight, 1)        self.assertFalse(tile.enclosed)        self.assertFalse(tile.has_rat)        self.assertEqual(tile.type, ".")    def test_init_custom_weight(self):        """Test Tile initialization with custom weight."""        tile = Tile((1, 1), weight=10)        self.assertEqual(tile.weight, 10)    def test_init_enclosed_true(self):        """Test Tile initialization with enclosed=True."""        tile = Tile((2, 2), enclosed=True)        self.assertTrue(tile.enclosed)        # Note: type is set before setEnclosed logic, so it remains "."        self.assertEqual(tile.type, ".")    def test_init_has_rat_true(self):        """Test Tile initialization with has_rat=True."""        tile = Tile((3, 3), has_rat=True)        self.assertTrue(tile.has_rat)        self.assertEqual(tile.type, "r")    def test_init_has_rat_false(self):        """Test Tile initialization with has_rat=False (default)."""        tile = Tile((0, 0), has_rat=False)        self.assertFalse(tile.has_rat)        self.assertEqual(tile.type, ".")    def test_init_all_parameters(self):        """Test Tile initialization with all parameters specified."""        tile = Tile((5, 5), weight=7, enclosed=True, has_rat=True)        self.assertEqual(tile.pos, (5, 5))        self.assertEqual(tile.weight, 7)        self.assertTrue(tile.enclosed)        self.assertTrue(tile.has_rat)        self.assertEqual(tile.type, "r")    def test_init_zero_weight(self):        """Test Tile initialization with zero weight."""        tile = Tile((0, 0), weight=0)        self.assertEqual(tile.weight, 0)    def test_init_negative_weight(self):        """Test Tile initialization with negative weight."""        tile = Tile((0, 0), weight=-5)        self.assertEqual(tile.weight, -5)    def test_set_enclosed_empty_tile(self):        """Test setEnclosed on an empty tile (type '.')."""        tile = Tile((0, 0))        self.assertEqual(tile.type, ".")        self.assertFalse(tile.enclosed)        tile.setEnclosed()        self.assertTrue(tile.enclosed)        self.assertEqual(tile.type, "*")    def test_set_enclosed_rat_tile(self):        """Test setEnclosed on a tile with rat (type 'r')."""        tile = Tile((0, 0), has_rat=True)        self.assertEqual(tile.type, "r")        tile.setEnclosed()        self.assertTrue(tile.enclosed)        self.assertEqual(tile.type, "R")    def test_set_enclosed_already_enclosed(self):        """Test setEnclosed on an already enclosed tile."""        tile = Tile((0, 0))        tile.setEnclosed()        self.assertEqual(tile.type, "*")        # Call setEnclosed again        tile.setEnclosed()        self.assertTrue(tile.enclosed)        # "*".capitalize() returns "*"        self.assertEqual(tile.type, "*")    def test_set_enclosed_multiple_calls(self):        """Test calling setEnclosed multiple times."""        tile = Tile((0, 0))        for _ in range(5):            tile.setEnclosed()        self.assertTrue(tile.enclosed)        self.assertEqual(tile.type, "*")    def test_repr_empty_tile(self):        """Test __repr__ for empty tile."""        tile = Tile((0, 0))        self.assertEqual(repr(tile), ".")        self.assertEqual(str(tile), ".")    def test_repr_rat_tile(self):        """Test __repr__ for tile with rat."""        tile = Tile((0, 0), has_rat=True)        self.assertEqual(repr(tile), "r")    def test_repr_enclosed_tile(self):        """Test __repr__ for enclosed tile."""        tile = Tile((0, 0))        tile.setEnclosed()        self.assertEqual(repr(tile), "*")    def test_pos_is_tuple(self):        """Test that pos attribute stores tuple correctly."""        tile = Tile((3, 7))        self.assertIsInstance(tile.pos, tuple)        self.assertEqual(len(tile.pos), 2)        self.assertEqual(tile.pos[0], 3)        self.assertEqual(tile.pos[1], 7)class TestCherry(unittest.TestCase):    """Test cases for the Cherry class."""    def setUp(self):        """Set up test fixtures for Cherry tests."""        self.default_cherry = Cherry((0, 0))        self.enclosed_cherry = Cherry((1, 1), enclosed=True)        self.custom_weight_cherry = Cherry((2, 2), weight=10)    def test_init_default_values(self):        """Test Cherry initialization with default values."""        cherry = Cherry((0, 0))        self.assertEqual(cherry.pos, (0, 0))        self.assertEqual(cherry.weight, 4)        self.assertFalse(cherry.enclosed)        self.assertEqual(cherry.type, "c")    def test_init_custom_weight(self):        """Test Cherry initialization with custom weight."""        cherry = Cherry((0, 0), weight=8)        self.assertEqual(cherry.weight, 8)    def test_init_enclosed_true(self):        """Test Cherry initialization with enclosed=True."""        cherry = Cherry((0, 0), enclosed=True)        self.assertTrue(cherry.enclosed)        self.assertEqual(cherry.type, "C")    def test_init_enclosed_false(self):        """Test Cherry initialization with enclosed=False."""        cherry = Cherry((0, 0), enclosed=False)        self.assertFalse(cherry.enclosed)        self.assertEqual(cherry.type, "c")    def test_inheritance_from_tile(self):        """Test that Cherry inherits from Tile."""        cherry = Cherry((0, 0))        self.assertIsInstance(cherry, Tile)    def test_set_enclosed_method(self):        """Test setEnclosed method on Cherry."""        cherry = Cherry((0, 0))        self.assertEqual(cherry.type, "c")        cherry.setEnclosed()        self.assertTrue(cherry.enclosed)        self.assertEqual(cherry.type, "C")    def test_repr_not_enclosed(self):        """Test __repr__ for non-enclosed Cherry."""        cherry = Cherry((0, 0))        self.assertEqual(repr(cherry), "c")    def test_repr_enclosed(self):        """Test __repr__ for enclosed Cherry."""        cherry = Cherry((0, 0), enclosed=True)        self.assertEqual(repr(cherry), "C")class TestBee(unittest.TestCase):    """Test cases for the Bee class."""    def setUp(self):        """Set up test fixtures for Bee tests."""        self.default_bee = Bee((0, 0))        self.enclosed_bee = Bee((1, 1), enclosed=True)        self.custom_weight_bee = Bee((2, 2), weight=-10)    def test_init_default_values(self):        """Test Bee initialization with default values."""        bee = Bee((0, 0))        self.assertEqual(bee.pos, (0, 0))        self.assertEqual(bee.weight, -4)        self.assertFalse(bee.enclosed)        self.assertEqual(bee.type, "b")    def test_init_enclosed_true(self):        """Test Bee initialization with enclosed=True."""        bee = Bee((0, 0), enclosed=True)        self.assertTrue(bee.enclosed)        self.assertEqual(bee.type, "B")    def test_init_enclosed_false(self):        """Test Bee initialization with enclosed=False."""        bee = Bee((0, 0), enclosed=False)        self.assertFalse(bee.enclosed)        self.assertEqual(bee.type, "b")    def test_inheritance_from_tile(self):        """Test that Bee inherits from Tile."""        bee = Bee((0, 0))        self.assertIsInstance(bee, Tile)    def test_set_enclosed_method(self):        """Test setEnclosed method on Bee."""        bee = Bee((0, 0))        self.assertEqual(bee.type, "b")        bee.setEnclosed()        self.assertTrue(bee.enclosed)        self.assertEqual(bee.type, "B")    def test_repr_not_enclosed(self):        """Test __repr__ for non-enclosed Bee."""        bee = Bee((0, 0))        self.assertEqual(repr(bee), "b")    def test_repr_enclosed(self):        """Test __repr__ for enclosed Bee."""        bee = Bee((0, 0), enclosed=True)        self.assertEqual(repr(bee), "B")class TestApple(unittest.TestCase):    """Test cases for the Apple class."""    def setUp(self):        """Set up test fixtures for Apple tests."""        self.default_apple = Apple((0, 0))        self.enclosed_apple = Apple((1, 1), enclosed=True)        self.custom_weight_apple = Apple((2, 2), weight=20)    def test_init_default_values(self):        """Test Apple initialization with default values."""        apple = Apple((0, 0))        self.assertEqual(apple.pos, (0, 0))        self.assertEqual(apple.weight, 11)        self.assertFalse(apple.enclosed)        self.assertEqual(apple.type, "a")    def test_init_enclosed_true(self):        """Test Apple initialization with enclosed=True."""        apple = Apple((0, 0), enclosed=True)        self.assertTrue(apple.enclosed)        self.assertEqual(apple.type, "A")    def test_init_enclosed_false(self):        """Test Apple initialization with enclosed=False."""        apple = Apple((0, 0), enclosed=False)        self.assertFalse(apple.enclosed)        self.assertEqual(apple.type, "a")    def test_inheritance_from_tile(self):        """Test that Apple inherits from Tile."""        apple = Apple((0, 0))        self.assertIsInstance(apple, Tile)    def test_set_enclosed_method(self):        """Test setEnclosed method on Apple."""        apple = Apple((0, 0))        self.assertEqual(apple.type, "a")        apple.setEnclosed()        self.assertTrue(apple.enclosed)        self.assertEqual(apple.type, "A")    def test_repr_not_enclosed(self):        """Test __repr__ for non-enclosed Apple."""        apple = Apple((0, 0))        self.assertEqual(repr(apple), "a")    def test_repr_enclosed(self):        """Test __repr__ for enclosed Apple."""        apple = Apple((0, 0), enclosed=True)        self.assertEqual(repr(apple), "A")class TestWall(unittest.TestCase):    """Test cases for the Wall class."""    def setUp(self):        """Set up test fixtures for Wall tests."""        self.default_wall = Wall((0, 0))        self.fixed_wall = Wall((1, 1), fixed=True)    def test_init_default_values(self):        """Test Wall initialization with default values."""        wall = Wall((0, 0))        self.assertEqual(wall.pos, (0, 0))        self.assertFalse(wall.fixed)        self.assertEqual(wall.type, "W")        self.assertEqual(wall.weight, 0)    def test_init_fixed_true(self):        """Test Wall initialization with fixed=True."""        wall = Wall((0, 0), fixed=True)        self.assertTrue(wall.fixed)        self.assertEqual(wall.type, "~")    def test_init_fixed_false(self):        """Test Wall initialization with fixed=False."""        wall = Wall((0, 0), fixed=False)        self.assertFalse(wall.fixed)        self.assertEqual(wall.type, "W")    def test_weight_always_zero(self):        """Test that Wall weight is always 0."""        wall1 = Wall((0, 0))        wall2 = Wall((1, 1), fixed=True)        self.assertEqual(wall1.weight, 0)        self.assertEqual(wall2.weight, 0)    def test_repr_movable_wall(self):        """Test __repr__ for movable wall."""        wall = Wall((0, 0))        self.assertEqual(repr(wall), " W ")    def test_repr_fixed_wall(self):        """Test __repr__ for fixed wall (water)."""        wall = Wall((0, 0), fixed=True)        self.assertEqual(repr(wall), " ~ ")    def test_pos_attribute(self):        """Test Wall pos attribute."""        wall = Wall((5, 10))        self.assertEqual(wall.pos, (5, 10))    def test_no_set_enclosed_method(self):        """Test that Wall does not have setEnclosed method."""        wall = Wall((0, 0))        self.assertFalse(hasattr(wall, 'setEnclosed'))class TestPortal(unittest.TestCase):    """Test cases for the Portal class."""    def setUp(self):        """Set up test fixtures for Portal tests."""        self.default_portal = Portal((0, 0), (5, 5))        self.enclosed_portal = Portal((1, 1), (6, 6), enclosed=True)    def test_init_default_values(self):        """Test Portal initialization with default values."""        portal = Portal((0, 0), (5, 5))        self.assertEqual(portal.pos, (0, 0))        self.assertEqual(portal.new_pos, (5, 5))        self.assertFalse(portal.enclosed)        self.assertEqual(portal.type, "p")        self.assertEqual(portal.weight, 1)    def test_init_enclosed_true(self):        """Test Portal initialization with enclosed=True."""        portal = Portal((0, 0), (5, 5), enclosed=True)        self.assertTrue(portal.enclosed)    def test_init_enclosed_false(self):        """Test Portal initialization with enclosed=False."""        portal = Portal((0, 0), (5, 5), enclosed=False)        self.assertFalse(portal.enclosed)    def test_new_pos_attribute(self):        """Test Portal new_pos (exit) attribute."""        portal = Portal((1, 2), (8, 9))        self.assertEqual(portal.new_pos, (8, 9))    def test_entry_and_exit_different(self):        """Test that entry and exit positions can be different."""        portal = Portal((0, 0), (10, 10))        self.assertNotEqual(portal.pos, portal.new_pos)    def test_inheritance_from_tile(self):        """Test that Portal inherits from Tile."""        portal = Portal((0, 0), (5, 5))        self.assertIsInstance(portal, Tile)    def test_repr(self):        """Test __repr__ for Portal."""        portal = Portal((0, 0), (5, 5))        self.assertEqual(repr(portal), "p")    def test_set_enclosed_method(self):        """Test setEnclosed method on Portal."""        portal = Portal((0, 0), (5, 5))        self.assertEqual(portal.type, "p")        portal.setEnclosed()        self.assertTrue(portal.enclosed)        # "p".capitalize() returns "P"        self.assertEqual(portal.type, "P")class TestTileComparisons(unittest.TestCase):    """Test cases comparing different tile types."""    def test_weight_ordering(self):        """Test relative weight ordering of different tile types."""        tile = Tile((0, 0))        cherry = Cherry((0, 0))        bee = Bee((0, 0))        apple = Apple((0, 0))        wall = Wall((0, 0))        portal = Portal((0, 0), (1, 1))        # Bee should have lowest (negative) weight        self.assertLess(bee.weight, tile.weight)        self.assertLess(bee.weight, cherry.weight)        self.assertLess(bee.weight, apple.weight)        # Apple should have highest weight        self.assertGreater(apple.weight, cherry.weight)        self.assertGreater(apple.weight, tile.weight)        # Wall should have zero weight        self.assertEqual(wall.weight, 0)        # Portal should have weight of 1        self.assertEqual(portal.weight, 1)    def test_all_tile_subclasses_have_set_enclosed(self):        """Test that all Tile subclasses have setEnclosed method."""        tile = Tile((0, 0))        cherry = Cherry((0, 0))        bee = Bee((0, 0))        apple = Apple((0, 0))        portal = Portal((0, 0), (1, 1))        for obj in [tile, cherry, bee, apple, portal]:            self.assertTrue(hasattr(obj, 'setEnclosed'))            self.assertTrue(callable(getattr(obj, 'setEnclosed')))    def test_type_markers_unique(self):        """Test that different tile types have unique markers."""        tile = Tile((0, 0))        cherry = Cherry((0, 0))        bee = Bee((0, 0))        apple = Apple((0, 0))        wall = Wall((0, 0))        portal = Portal((0, 0), (1, 1))        markers = [tile.type, cherry.type, bee.type, apple.type,                   wall.type, portal.type]        # All markers should be unique        self.assertEqual(len(markers), len(set(markers)))    def test_enclosed_markers_unique(self):        """Test that enclosed tile types have unique uppercase markers."""        cherry = Cherry((0, 0), enclosed=True)        bee = Bee((0, 0), enclosed=True)        apple = Apple((0, 0), enclosed=True)        markers = [cherry.type, bee.type, apple.type]        # All enclosed markers should be unique        self.assertEqual(len(markers), len(set(markers)))        # All should be uppercase        for marker in markers:            self.assertTrue(marker.isupper())class TestIntegration(unittest.TestCase):    """Integration tests simulating real usage scenarios."""    def test_create_simple_board(self):        """Test creating a simple board with various elements."""        # Create a 3x3 board representation        board = [            [Tile((0, 0)), Wall((0, 1)), Tile((0, 2))],            [Cherry((1, 0)), Bee((1, 1)), Apple((1, 2))],            [Portal((2, 0), (0, 2)), Tile((2, 1)), Wall((2, 2), fixed=True)]        ]        # Verify board structure        self.assertEqual(len(board), 3)        self.assertEqual(len(board[0]), 3)        # Verify specific elements        self.assertIsInstance(board[0][1], Wall)        self.assertIsInstance(board[1][0], Cherry)        self.assertIsInstance(board[1][1], Bee)        self.assertIsInstance(board[1][2], Apple)        self.assertIsInstance(board[2][0], Portal)    def test_calculate_board_score(self):        """Test calculating total score from board tiles."""        tiles = [            Tile((0, 0)),      # weight: 1            Cherry((0, 1)),    # weight: 4            Bee((0, 2)),       # weight: -4            Apple((0, 3)),     # weight: 11            Wall((0, 4)),      # weight: 0            Portal((0, 5), (1, 1))  # weight: 1        ]        total_weight = sum(tile.weight for tile in tiles)        expected = 1 + 4 + (-4) + 11 + 0 + 1        self.assertEqual(total_weight, expected)        self.assertEqual(total_weight, 13)    def test_enclose_multiple_tiles(self):        """Test enclosing multiple tiles and checking their states."""        tiles = [            Tile((0, 0)),            Cherry((0, 1)),            Bee((0, 2)),            Apple((0, 3))        ]        # Enclose all tiles        for tile in tiles:            tile.setEnclosed()        # Verify all are enclosed        for tile in tiles:            self.assertTrue(tile.enclosed)        # Verify type markers changed appropriately        self.assertEqual(tiles[0].type, "*")  # Tile        self.assertEqual(tiles[1].type, "C")  # Cherry        self.assertEqual(tiles[2].type, "B")  # Bee        self.assertEqual(tiles[3].type, "A")  # Appleif __name__ == '__main__':    # Run tests with verbosity    unittest.main(verbosity=2)